const Theme={currentTheme:'light',init(){const html=document.documentElement;const savedTheme=localStorage.getItem('theme');const systemPrefersDark=window.matchMedia('(prefers-color-scheme:dark)').matches;this.currentTheme=savedTheme ||(systemPrefersDark ? 'dark':'light');this.applyTheme(this.currentTheme);window.matchMedia('(prefers-color-scheme:dark)').addEventListener('change',(e)=>{if(!localStorage.getItem('theme')){this.currentTheme=e.matches ? 'dark':'light';this.applyTheme(this.currentTheme);}});document.addEventListener('click',(e)=>{const themeToggle=e.target.closest('.theme-toggle');if(themeToggle){this.toggle();}});document.addEventListener('componentLoaded',(e)=>{if(e.detail.url && e.detail.url.includes('header.html')){this.updateThemeIcon();}});this.updateThemeIcon();},applyTheme(theme){const html=document.documentElement;if(theme==='dark'){html.classList.add('dark-mode');}else{html.classList.remove('dark-mode');}this.currentTheme=theme;this.updateThemeIcon();},toggle(){const newTheme=this.currentTheme==='light' ? 'dark':'light';this.setTheme(newTheme);},setTheme(theme){this.currentTheme=theme;localStorage.setItem('theme',theme);this.applyTheme(theme);if(typeof Toast !=='undefined'){Toast.info(`${theme==='dark' ? 'Dark':'Light'}mode enabled`,2000);}},getTheme(){return this.currentTheme;},isDark(){return this.currentTheme==='dark';},updateThemeIcon(){const themeIcon=document.getElementById('themeIcon');if(themeIcon){if(this.currentTheme==='dark'){themeIcon.className='bi bi-sun-fill';}else{themeIcon.className='bi bi-moon-fill';}}}};if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',()=> Theme.init());}else{Theme.init();}window.toggleTheme=()=> Theme.toggle();window.setTheme=(theme)=> Theme.setTheme(theme);window.getTheme=()=> Theme.getTheme();window.isDarkMode=()=> Theme.isDark();if(typeof module !=='undefined' && module.exports){module.exports=Theme;}